          color: var(--primary);
          transition: transform 0.2s;
        }

        .connector-btn:hover .connect-link {
          transform: translateX(2px);
          color: var(--text-primary);
        }

        /* --- Diagnostics Console --- */
        .console-panel {
          gap: 16px;
        }

        .bulk-actions {
          display: flex;
          flex-direction: column;
          gap: 10px;
        }

        .btn-console {
          width: 100%;
          justify-content: flex-start;
          padding: 14px 18px;
          font-size: 0.88rem;
        }

        .btn-icon {
          width: 16px;
          height: 16px;
          flex-shrink: 0;
        }

        /* --- Stores View Panel --- */
        .main-column {
          min-width: 0;
        }

        .panel-header-row {
          display: flex;
          justify-content: space-between;
          align-items: flex-start;
          gap: 20px;
          border-bottom: 1px solid var(--border-color);
          padding-bottom: 16px;
        }

        .btn-refresh-all {
          padding: 8px 16px;
          font-size: 0.85rem;
        }

        /* Loading & Empty States */
        .grid-loader {
          height: 250px;
          display: flex;
          flex-direction: column;
          align-items: center;
          justify-content: center;
          color: var(--text-secondary);
          gap: 14px;
        }

        .spinner {
          width: 36px;
          height: 36px;
          border: 3px solid rgba(99, 102, 241, 0.2);
          border-top-color: var(--primary);
          border-radius: 50%;
          animation: spin 1s linear infinite;
        }

        .spinner-sm {
          width: 16px;
          height: 16px;
          border: 2px solid rgba(255, 255, 255, 0.2);
          border-top-color: #fff;
          border-radius: 50%;
          animation: spin 0.8s linear infinite;
          display: inline-block;
          flex-shrink: 0;
        }

        @keyframes spin { to { transform: rotate(360deg); } }

        .empty-state {
          display: flex;
          flex-direction: column;
          align-items: center;
          justify-content: center;
          padding: 60px 40px;
          text-align: center;
          background: rgba(255, 255, 255, 0.01);
          border-style: dashed;
        }

        .empty-icon {
          width: 64px;
          height: 64px;
          border-radius: 50%;
          background: rgba(255, 255, 255, 0.02);
          display: flex;
          align-items: center;
          justify-content: center;
          color: var(--text-muted);
          margin-bottom: 16px;
        }

        .empty-icon :global(svg) {
          width: 32px;
          height: 32px;
        }

        .empty-state h4 {
          font-size: 1.1rem;
          color: var(--text-primary);
          margin-bottom: 6px;
        }

        .empty-state p {
          font-size: 0.88rem;
          color: var(--text-muted);
          max-width: 380px;
          line-height: 1.4;
        }

        /* --- Connected Stores Grid --- */
        .stores-grid {
          display: grid;
          grid-template-columns: repeat(auto-fill, minmax(320px, 1fr));
          gap: 20px;
          margin-top: 10px;
        }

        .store-card {
          display: flex;
          flex-direction: column;
          padding: 0;
          overflow: hidden;
          background: rgba(16, 22, 38, 0.4);
          transition: all 0.3s cubic-bezier(0.25, 0.8, 0.25, 1);
        }

        .store-card:hover {
          transform: translateY(-4px);
        }

        /* Card Borders based on brand */
        .tiktok-border:hover { border-color: #00f2fe; }
        .shopee-border:hover { border-color: #ff5722; }
        .lazada-border:hover { border-color: #000080; }

        .store-brand-header {
          padding: 16px 20px;
          display: flex;
          align-items: center;
          position: relative;
        }

        .bg-tiktok-gradient { background: linear-gradient(135deg, #090d16 0%, #1c2742 100%); border-bottom: 1px solid rgba(0, 242, 254, 0.15); }
        .bg-shopee-gradient { background: linear-gradient(135deg, #2c140a 0%, #3e1b0c 100%); border-bottom: 1px solid rgba(255, 87, 34, 0.15); }
        .bg-lazada-gradient { background: linear-gradient(135deg, #060a16 0%, #0d1730 100%); border-bottom: 1px solid rgba(0, 0, 128, 0.15); }

        .brand-logo-glow {
          width: 32px;
          height: 32px;
          border-radius: 50%;
          background: rgba(255, 255, 255, 0.05);
          border: 1px solid rgba(255, 255, 255, 0.1);
          color: #fff;
          font-weight: 700;
          font-size: 0.95rem;
          display: flex;
          align-items: center;
          justify-content: center;
          margin-right: 12px;
          flex-shrink: 0;
        }

        .brand-meta {
          flex-grow: 1;
        }

        .store-name {
          font-size: 0.98rem;
          font-weight: 600;
          color: var(--text-primary);
          white-space: nowrap;
          overflow: hidden;
          text-overflow: ellipsis;
          max-width: 140px;
        }

        .store-marketplace-tag {
          font-size: 0.72rem;
          color: var(--text-secondary);
          text-transform: uppercase;
          letter-spacing: 0.05em;
          display: block;
        }

        /* Pulse indicators */
        .pulse-dot::before {
          content: '';
          display: inline-block;
          width: 6px;
          height: 6px;
          border-radius: 50%;
          margin-right: 6px;
          animation: pulseGlow 1.8s infinite;
        }

        .badge-success.pulse-dot::before { background: var(--success); }
        .badge-warning.pulse-dot::before { background: var(--warning); }

        @keyframes pulseGlow {
          0% { transform: scale(0.95); box-shadow: 0 0 0 0 rgba(16, 185, 129, 0.7); }
          70% { transform: scale(1); box-shadow: 0 0 0 5px rgba(16, 185, 129, 0); }
          100% { transform: scale(0.95); box-shadow: 0 0 0 0 rgba(16, 185, 129, 0); }
        }

        .store-body {
          padding: 16px 20px;
          display: flex;
          flex-direction: column;
          gap: 12px;
          border-bottom: 1px solid var(--border-color);
          flex-grow: 1;
        }

        .detail-item {
          display: flex;
          justify-content: space-between;
          align-items: center;
          gap: 10px;
          font-size: 0.85rem;
        }

        .detail-lbl {
          color: var(--text-muted);
        }

        .detail-val {
          color: var(--text-primary);
          font-weight: 500;
        }

        .font-mono { font-family: monospace; letter-spacing: -0.01em; }
        .font-bold { font-weight: 700; }
        .text-error { color: var(--error); }
        .text-warning { color: var(--warning); }

        .store-actions {
          padding: 12px 16px;
          background: rgba(0, 0, 0, 0.15);
          display: flex;
          align-items: center;
          gap: 8px;
        }

        .btn-action {
          display: flex;
          align-items: center;
          justify-content: center;
          gap: 6px;
          padding: 8px 12px;
          border-radius: var(--radius-sm);
          font-size: 0.78rem;
          font-weight: 600;
          cursor: pointer;
          border: 1px solid var(--glass-border);
          background: rgba(255, 255, 255, 0.02);
          color: var(--text-secondary);
          transition: all 0.2s;
        }

        .btn-action:hover {
          color: var(--text-primary);
          background: rgba(255, 255, 255, 0.05);
        }

        .act-icon {
          width: 14px;
          height: 14px;
        }

        .btn-health:hover {
          border-color: var(--primary);
          color: #818cf8;
        }

        .btn-refresh:hover {
          border-color: var(--success);
          color: #34d399;
        }

        .btn-delete {
          padding: 8px 10px;
        }

        .btn-delete:hover {
          border-color: var(--error);
          background: rgba(239, 68, 68, 0.05);
          color: var(--error);
        }

        /* --- Modal overlay --- */
        .modal-overlay {
          position: fixed;
          top: 0;
          left: 0;
          width: 100vw;
          height: 100vh;
          background: rgba(0, 0, 0, 0.75);
          backdrop-filter: blur(10px);
          display: flex;
          align-items: center;
          justify-content: center;
          z-index: 999;
          animation: modalOverlayEnter 0.3s ease;
        }

        @keyframes modalOverlayEnter { from { opacity: 0; } to { opacity: 1; } }

        .modal-content {
          max-width: 460px;
          width: 90%;
          background: rgba(13, 18, 33, 0.9);
          border: 1px solid rgba(255, 255, 255, 0.08);
          padding: 32px;
          animation: modalContentEnter 0.4s cubic-bezier(0.16, 1, 0.3, 1);
        }

        @keyframes modalContentEnter { 
          from { opacity: 0; transform: scale(0.92) translateY(10px); } 
          to { opacity: 1; transform: scale(1) translateY(0); } 
        }

        .modal-header {
          display: flex;
          align-items: center;
          gap: 14px;
          margin-bottom: 16px;
        }

        .modal-header h3 {
          font-size: 1.25rem;
          font-weight: 700;
          color: var(--text-primary);
        }

        .warn-icon {
          width: 28px;
          height: 28px;
          color: var(--warning);
          flex-shrink: 0;
        }

        .modal-body {
          font-size: 0.9rem;
          color: var(--text-secondary);
          line-height: 1.5;
          margin-bottom: 24px;
        }

        .modal-footer {
          display: flex;
          justify-content: flex-end;
          gap: 12px;
        }

        .btn-danger {
          background: var(--error);
          color: #fff;
          border: none;
          padding: 10px 20px;
          border-radius: var(--radius-md);
          font-weight: 600;
          cursor: pointer;
          transition: filter 0.2s;
        }

        .btn-danger:hover {
          filter: brightness(1.1);
        }
      `}</style>
    </div>
  );
}

